public inline fun <C> fold(ifLeft: (left: A) -> C, ifRight: (right: B) -> C): C {
  contract {
    callsInPlace(ifLeft, InvocationKind.AT_MOST_ONCE)
    callsInPlace(ifRight, InvocationKind.AT_MOST_ONCE)
    (this@Either is Left) holdsIn ifLeft
    (this@Either is Right) holdsIn ifRight
  }
  return when (this) {
    is Right -> ifRight(value)
    is Left -> ifLeft(value)
  }
}

public inline fun <R> catch(f: () -> R): Either<Throwable, R> {
  contract { callsInPlace(f, InvocationKind.AT_MOST_ONCE) }
  return arrow.core.raise.catch(f, ::Right, ::Left)
}

@JvmStatic
public inline fun <reified T : Throwable, R> catchOrThrow(f: () -> R): Either<T, R> {
  contract { callsInPlace(f, InvocationKind.AT_MOST_ONCE) }
  return arrow.core.raise.catch<T, _, _>(f, ::Right, ::Left)
}

public inline fun <A> catch(f: SingletonRaise<None>.() -> A): Option<A> {
  contract { callsInPlace(f, InvocationKind.AT_MOST_ONCE) }
  return catch({ None }, f)
}

@JvmStatic
@JvmName("tryCatch")
public inline fun <A> catch(recover: (Throwable) -> Option<A>, f: SingletonRaise<None>.() -> A): Option<A> {
  contract {
    callsInPlace(f, InvocationKind.AT_MOST_ONCE)
    callsInPlace(recover, InvocationKind.AT_MOST_ONCE)
  }
  return recover({ f(SingletonRaise(this)).some() }, { None }, recover)
}

public inline fun <A> Option<A>.combine(other: Option<A>, combine: (A, A) -> A): Option<A> {
  contract {
    callsInPlace(combine, InvocationKind.AT_MOST_ONCE)
    (this@combine is Some && other is Some) holdsIn combine
  }
  return when (this) {
    is Some -> when (other) {
      is Some -> Some(combine(value, other.value))
      None -> this
    }

    None -> other
  }
}

@JvmName("_foldOrThrow")
public inline fun <Error, A, B> fold(
  block: Raise<Error>.() -> A,
  recover: (error: Error) -> B,
  transform: (value: A) -> B,
): B {
  contract {
    callsInPlace(block, AT_MOST_ONCE)
    callsInPlace(recover, AT_MOST_ONCE)
    callsInPlace(transform, AT_MOST_ONCE)
  }
  return fold(block, { throw it }, recover, transform)
}

@PublishedApi
internal class DefaultRaise(@PublishedApi internal val isTraced: Boolean) : Raise<Any?> {
  private val isActive = AtomicBoolean(true)

  @PublishedApi @IgnorableReturnValue
  internal fun complete(): Boolean = isActive.getAndSet(false)

  @OptIn(DelicateRaiseApi::class)
  override fun raise(r: Any?): Nothing = when {
    isActive.value -> throw if (isTraced) Traced(r, this) else NoTrace(r, this)
    else -> throw RaiseLeakedException()
  }
}

public inline fun <Error, A> ior(noinline combineError: (Error, Error) -> Error, block: IorRaise<Error>.() -> A): Ior<Error, A> {
  contract { callsInPlace(block, InvocationKind.AT_MOST_ONCE) }
  val state: Atomic<Any?> = Atomic(EmptyValue)
  return fold(
    { block(IorRaise(combineError, state, this)) },
    { e -> Ior.Left(EmptyValue.combine(state.get(), e, combineError)) },
    { a -> EmptyValue.fold(state.get(), { Ior.Right(a) }, { e: Error -> Ior.Both(e, a) }) },
  )
}

internal fun <R> copyWithAnotherColumnType(columnType: ColumnType<R & Any>, body: (Column<R>.() -> Unit)? = null): Column<R> {
    val newColumn: Column<R> = Column(table, name, columnType)
    newColumn.foreignKey = foreignKey
    @Suppress("UNCHECKED_CAST")
    newColumn.dbDefaultValue = dbDefaultValue as Expression<R>?
    newColumn.isDatabaseGenerated = isDatabaseGenerated
    newColumn.extraDefinitions = extraDefinitions
    newColumn.columnComment = columnComment
    body?.let { newColumn.it() }

    if (defaultValueFun != null) {
        require(newColumn.defaultValueFun != null) { "defaultValueFun was lost on cloning the column" }
    }
    return newColumn
}

class LongColumnType : ColumnType<Long>() {
    override fun sqlType(): String = currentDialect.dataTypeProvider.longType()
    override fun valueFromDB(value: Any): Long = when (value) {
        is Long -> value
        is Number -> value.toLong()
        is String -> value.toLong()
        else -> error("Unexpected value of type Long: $value of ${value::class.qualifiedName}")
    }
}

@OptIn(InternalForInheritanceCoroutinesApi::class)
@Suppress("UNCHECKED_CAST")
private open class DeferredCoroutine<T>(
    parentContext: CoroutineContext,
    active: Boolean
) : AbstractCoroutine<T>(parentContext, true, active = active), Deferred<T> {
    override fun getCompleted(): T = getCompletedInternal() as T
    override suspend fun await(): T = awaitInternal() as T
    override val onAwait: SelectClause1<T> get() = onAwaitInternal as SelectClause1<T>
}

internal inline fun <T, R1 : T, R2 : T> Json.selectMapMode(
    mapDescriptor: SerialDescriptor,
    ifMap: () -> R1,
    ifList: () -> R2
): T {
    val keyDescriptor = mapDescriptor.getElementDescriptor(0).carrierDescriptor(serializersModule)
    val keyKind = keyDescriptor.kind

    return if (keyKind is PrimitiveKind || keyKind == SerialKind.ENUM) {
        ifMap()
    } else if (configuration.allowStructuredMapKeys) {
        ifList()
    } else {
        throw InvalidKeyKindException(keyDescriptor)
    }
}

override fun toString(): String {
    return when (val parentRoute = parent?.toString()) {
        null -> when (selector) {
            is TrailingSlashRouteSelector -> "/"
            else -> "/$selector"
        }

        else -> when (selector) {
            is TrailingSlashRouteSelector -> if (parentRoute.endsWith('/')) parentRoute else "$parentRoute/"
            else -> if (parentRoute.endsWith('/')) "$parentRoute$selector" else "$parentRoute/$selector"
        }
    }
}

when (type) {
    "Function" -> "JsFunction<*, *>"
    "any" -> "JsAny?"
    "number" -> when (name) {
        "f32" -> "JsFloat"
        "f64" -> "JsDouble"
        "i32" -> "JsInt"
        else -> error("No type parameter for '$name: $type'")
    }

    "bigint" -> "BigInt"
    "never" -> "Void"
    else -> error("No type parameter for type '$type'")
}

try {
    val closeRecord = TLSRecord(
        TLSRecordType.Alert,
        packet = buildPacket {
            writeByte(TLSAlertLevel.WARNING.code.toByte())
            writeByte(TLSAlertType.CloseNotify.code.toByte())
        }
    )
    val record = if (useCipher) cipher.encrypt(closeRecord) else closeRecord
    rawOutput.writeRecord(record)
    rawOutput.flushAndClose()
} finally {
    closeTask.complete()
}

try {
    base.input.consumeEach { record ->
        val packet = record.packet
        val length = packet.remaining
        when (record.type) {
            TLSRecordType.ApplicationData -> {
                pipe.writePacket(record.packet)
                pipe.flush()
            }
            else -> throw TLSException("Unexpected record ${record.type} ($length bytes)")
        }
    }
} catch (_: Throwable) {
} finally {
    pipe.flushAndClose()
}

