if (last == NUMBER_CHAR_DIGIT && fitsInLong && (value != Long.MIN_VALUE || negative)) {
  peekedLong = if (negative) value else -value
  buffer.skip(i.toLong())
  PEEKED_LONG.also { peeked = it }
} else if (last == NUMBER_CHAR_DIGIT || last == NUMBER_CHAR_FRACTION_DIGIT || last == NUMBER_CHAR_EXP_DIGIT) {
  peekedNumberLength = i
  PEEKED_NUMBER.also { peeked = it }
} else {
  PEEKED_NONE
}

if (currentIteratorWrapper.iterator.hasNext()) {
  val next = currentIteratorWrapper.iterator.next()
  peekedData = next

  peekedToken = when (currentIteratorWrapper) {
    is IteratorWrapper.EntryIterator -> JsonReader.Token.NAME
    is IteratorWrapper.StandardIterator -> anyToToken(next)
  }
} else {
  peekedToken = if (path[stackSize - 1] is Int) {
    JsonReader.Token.END_ARRAY
  } else {
    JsonReader.Token.END_OBJECT
  }
}

when (it.kind) {
  RTypeKind.SCALAR -> it.toGQLScalarTypeDefinition()
  RTypeKind.OBJECT -> it.toGQLObjectTypeDefinition()
  RTypeKind.INTERFACE -> it.toGQLInterfaceTypeDefinition()
  RTypeKind.UNION -> it.toGQLUnionTypeDefinition()
  RTypeKind.ENUM -> it.toGQLEnumTypeDefinition()
  RTypeKind.INPUT_OBJECT -> it.toGQLInputObjectTypeDefinition()
  else -> throw ConversionException("Unknown type kind: ${it.kind}")
}

when (this.kind) {
  RTypeKind.NON_NULL -> GQLNonNullType(
      type = ofType?.toGQLType() ?: throw ConversionException("ofType must not be null for non null types")
  )

  RTypeKind.LIST -> GQLListType(
      type = ofType?.toGQLType() ?: throw ConversionException("ofType must not be null for list types")
  )

  else -> GQLNamedType(
      name = name!!
  )
}

