if (controlledInputsValuesWeakMap.has(inputElement)) {
    if (type == InputType.Radio) {
        controlledRadioGroups[inputElement.name]?.forEach { radio ->
            radio.checked = controlledInputsValuesWeakMap.get(radio).toString().toBoolean()
        }
        inputElement.checked = controlledInputsValuesWeakMap.get(inputElement).toString().toBoolean()
        return
    }

    if (type == InputType.Checkbox) {
        inputElement.checked = controlledInputsValuesWeakMap.get(inputElement).toString().toBoolean()
    } else {
        inputElement.value = controlledInputsValuesWeakMap.get(inputElement).toString()
    }
}

when (node) {
    is HTMLElement, is SVGElement -> {
        node.removeAttribute("style")

        val style = node.unsafeCast<ElementCSSInlineStyle>().style

        styleApplier.properties.forEach { (name, value, important) ->
            style.setProperty(name, value.toString(), if (important) "important" else "")
        }

        styleApplier.variables.forEach { (name, value) ->
            style.setProperty(name, value.toString())
        }
    }
}

for (unionType in UNION_TYPES) {
    result = result.flatMap { source ->
        if (": $unionType" in source) {
            val (t1, t2) = unionType.split(" | ")

            sequenceOf(
                source.replace(": $unionType", ": $t1"),
                source.replace(": $unionType", ": $t2"),
            )
        } else sequenceOf(source)
    }
}

for ((name, body, optPkg) in eventDeclarations) {
    val pkg = optPkg ?: EVENT_INFO_MAP.getValue(name.substringBefore("."))
        .fqn
        .substringBeforeLast(".")

    val targetDir = sourceDir
        .resolve(pkg.replace(".", "/"))
        .also { it.mkdirs() }

    targetDir.resolve("$name.kt")
        .also { check(!it.exists()) { "Duplicated file: ${it.name}" } }
        .writeCode(fileContent(body = body, pkg = pkg))
}

if (enumMode && name !in EXCLUDED_ENUMS) {
    if (!items.all { it.startsWith('"') })
        return null

    val enumBody = if (name == NAMED_COLOR) {
        val constants = items.toUnionValues()
            .map { UnionConstant(it, NAMED_COLOR_MAP.getValue(it)) }

        unionBodyByConstants(COLOR, constants)
            .replaceFirst(COLOR, NAMED_COLOR)
    } else {
        sealedUnionBody(name, items.toUnionValues())
    }

    return ConversionResult(name, enumBody)
}

while (pointBegin != input.length) {
    val pointEnd = input.indexOf('.', pointBegin + 1).let { if (it == -1) input.length else it }

    input.substring(pointBegin + 1, pointEnd).toIntOrNull()?.let { pos ->
        val element = input.take(pointBegin)
        val newSize = pos + 1
        listElements[element] = listElements[element]?.let { maxOf(it, newSize) } ?: newSize
    }
    pointBegin = pointEnd
}

try {
    previewFacade.getMethod("render", *renderArgsClasses)
} catch (e: NoSuchMethodException) {
    val signature =
        "${previewFacade.canonicalName}#render(${renderArgsClasses.joinToString(", ") { it.simpleName }})"
    val possibleCandidates = previewFacade.methods.filter { it.name == "render" }
    throw RuntimeException("Could not find method '$signature'. Possible candidates: \n${possibleCandidates.joinToString("\n") { "* ${it}" }}", e)
}

if ("\n" in source) {
    val comment = source.substringBeforeLast("\n")
        .replace(";--\n", ";\n") // RESTORE
        .let(::formatComment)

    if ("@deprecated" in comment)
        return null

    val member = convertMember(source.substringAfterLast("\n"), typeProvider, extensionsCollector, comment)
        .takeIf { it?.trim()?.isNotEmpty() == true }
        ?: return null

    return comment + "\n" + member
}
